+
+    private static String collapseLeadingSlashes(String s) {
+        final int len = s.length();
+        int i = 0;
+
+        // Find the last consecutive / character
+        while (i < len && s.charAt(i) == '/') {
+            i++;
+        }
+
+        // No leading slashes
+        if (i == 0) {
+            return s;
+        }
+
+        // Nothing but slashes
+        if (i == len) {
+            return "/";
+        }
+
+        // Multiple; remove all but one
+        return s.substring(i - 1);
+    }
 }

